#include<bits/stdc++.h>
using namespace std;
int main() {
	int n, a[10001], m, b[10001],g,num;
	cin >> n;
	for (int i = 0; i < n; i++) {
		cin >> a[i];
	}cin>>m;
	for(int i=0;i<n;i++){
		cin>>g;
		b[i]=a[g];
		num=0;
		for(int j=0;j<n;j++){
			if(b[j]>b[i]){
				swap(b[j],b[i]);
				num++;
			}
		}cout<<num<<endl;
		
	}
	return 0;
}
